import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Card, Input, Button, Avatar, Chip, ScrollArea, icon } from 'decantr/components';

code.example:
function ChatInterface() {
  const { div, span, p } = tags;
  const [input, setInput] = createSignal('');
  const [messages, setMessages] = createSignal([
    { role: 'assistant', text: 'Hi! I\'m your AI chef assistant. Ask me anything about cooking!' }
  ]);
  const suggestions = ['What can I make with chicken?', 'Suggest a quick dinner', 'How do I make pasta from scratch?'];

  const send = () => {
    if (!input()) return;
    setMessages([...messages(), { role: 'user', text: input() }]);
    setInput('');
  };

  return div({ class: css('_flex _col _h[calc(100vh-200px)] _b1 _r4 _overflow[hidden]') },
    ScrollArea({ class: css('_flex1 _p4') },
      div({ class: css('_flex _col _gap3') },
        ...messages().map(m =>
          div({ class: css(m.role === 'user' ? '_flex _jce' : '_flex _gap2') },
            m.role === 'assistant' ? Avatar({ size: 'sm', fallback: 'AI' }) : null,
            div({ class: css(`_p3 _r4 _mw[70%] ${m.role === 'user' ? '_bgprimary _fgprimary' : '_bgmuted'}`) },
              p({}, m.text)
            )
          )
        )
      )
    ),
    div({ class: css('_flex _gap2 _p3 _borderb _flexWrap') },
      ...suggestions.map(s =>
        Chip({ variant: 'outline', onclick: () => setInput(s) }, s)
      )
    ),
    div({ class: css('_flex _gap2 _p3 _bordert') },
      Input({ placeholder: 'Ask your chef assistant...', value: input, onchange: e => setInput(e.target.value), class: css('_flex1') }),
      Button({ variant: 'primary', onclick: send }, icon('send'))
    )
  );
}
